class APIServerRepository extends Repository {
  static final _fc =
      failureCodeBuilder.category('DASR'); // Data-ApiServerRepository
  static final _logger = FimberLog('APIServerRepository');
  static const _searchCountLimit = 10000;

  final ProfileStorage profileStorage;
  late final APIServerClient _client;

  APIServerRepository({
    required this.profileStorage,
    required Locale locale,
    required String? appVersion,
  }) {
    _client = APIServerClient(
      locale: locale,
      appVersion: appVersion,
    );
  }

  ResourceData _reprocessResource(
    ResourceData resource,
    String teamId,

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/store_kit_2_wrappers.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/data/models/plan.dart';

@immutable
class AppStoreProduct extends SK2Product {
  AppStoreProduct({
    required this.planType,
    required this.productDetails,
    required super.id,
    required super.displayName,
    required super.displayPrice,
    required super.description,
    required super.price,
    required super.type,
    required super.priceLocale,
    super.subscription,
  });

  final PlanType planType;

  final ProductDetails productDetails;
}

// プラン種別
enum PlanType {
  light(id: Constants.appStoreProductIdLight),
  standard(id: Constants.appStoreProductIdStandard),
  premium(id: Constants.appStoreProductIdPremium);

  const PlanType({required this.id});

  final String id;

  factory PlanType.fromId(String id) {
    return PlanType.values.firstWhere(
      (e) => e.id == id,
      orElse: () => PlanType.light,
    );
  }

  Plan get toPlan => switch (this) {
        light => defaultPlans[0],
        standard => defaultPlans[1],
        premium => defaultPlans[2]
      };
}

const defaultPlans = [
  Plan(
    name: 'LIGHT',
    id: '00000001-0000-0050-0000-000000000000',
    maxBalls: 50,
    maxAiCoachs: 1,
  ),
  Plan(
    name: 'STANDARD',
    id: '00000001-0000-0100-0000-000000000000',
    maxBalls: 250,
    maxAiCoachs: 5,
  ),
  Plan(
    name: 'PREMIUM',
