import { DataSource } from 'typeorm';

import { Coded, CodedMethod, Service } from '@/app/common/decorators';
import { SubscriptionGroup } from '@/app/models/subscription-group';
import { BaseService } from '@/app/services/base-service';

@Coded('SPGR')
@Service()
@Injectable()
export class SubscriptionGroupsService extends BaseService {
  private readonly logger = new Logger(SubscriptionGroupsService.name);

  constructor(private readonly dataSource: DataSource) {
    super();
  }

  static readonly ERROR_CODES = {};

  get EC() {
    return SubscriptionGroupsService.ERROR_CODES;
  }

  @CodedMethod('GPG')
  async getSubscriptionGroups(): Promise<{
    subscriptionGroups: SubscriptionGroup[];
    total: number;
  }> {
    const subscriptionGroups = await this.dataSource.manager.find(
      SubscriptionGroup,
      {
        where: {
          isActive: true,
          teamType: 'single',
        },
        relations: {
          subscriptions: true,
        },
        order: {
          createdAt: 'ASC',
        },
      },
    );

    return {
      subscriptionGroups,
      total: subscriptionGroups.length,
    };
  }
}

