import {
  Column,
  Entity,
  JoinColumn,
  JoinTable,
  ManyToMany,
  ManyToOne,
  OneToMany,
} from 'typeorm';

import { Item } from '@/app/models/item';
import { SubscriptionItem } from '@/app/models/subscription-item';
import { TeamSubscription } from '@/app/models/team-subscription';

import { SubscriptionGroup } from './subscription-group';

interface StripePlatformConfig {
  productId: string;
  priceId: string;
}

interface ApplePlatformConfig {
  productId: string;
}

export interface PlatformConfig {
  stripe?: StripePlatformConfig;
  apple?: ApplePlatformConfig;
}

@Entity('subscriptions', { schema: 'public' })
export class Subscription {
  @Column('uuid', {
    primary: true,
    name: 'id',
    default: () => 'gen_random_uuid()',
  })
  id: string;

  @Column('text', { name: 'name' })
  name: string;

  @Column('text', { name: 'description', nullable: true })
  description: string | null;

  @Column('boolean', { name: 'is_paid' })
  isPaid: boolean;

  @Column('jsonb', { name: 'platform_config', default: {} })
  platformConfig: PlatformConfig;

  @Column('timestamp with time zone', {
    name: 'created_at',
    default: () => 'now()',
  })
  createdAt: Date;

  @Column('timestamp with time zone', {
    name: 'updated_at',
    default: () => 'now()',
  })
  updatedAt: Date;

  @OneToMany(() => SubscriptionItem, (si) => si.subscription)
  subscriptionItems: SubscriptionItem[];

  @OneToMany(() => TeamSubscription, (ts) => ts.subscription)
  teamSubscriptions: TeamSubscription[];

  @ManyToMany(() => Item, (i) => i.subscriptions)
  @JoinTable({
    name: 'subscriptions_items',
    joinColumn: { name: 'subscription_id', referencedColumnName: 'id' },
    inverseJoinColumn: { name: 'item_id', referencedColumnName: 'id' },
  })
  items: Item[];

  @Column('uuid', { name: 'subscription_group_id', nullable: true })
  subscriptionGroupId: string | null;

  @ManyToOne(
    () => SubscriptionGroup,
    (subscriptionGroup) => subscriptionGroup.subscriptions,
    {
      nullable: true,
    },
  )
  @JoinColumn([{ name: 'subscription_group_id', referencedColumnName: 'id' }])
  subscriptionGroup: SubscriptionGroup | null;
}

