  CodedMethod,
} from '@/app/common/decorators';
import { AppExtendedRequest } from '@/app/common/types';
import { BaseController } from '@/app/controllers/base-controller';
import { BallsService } from '@/app/services/balls.service';
import { SubscriptionGroupsService } from '@/app/services/subscription-groups.service';

@Coded('CMST')
@ApiDefault()
@Authorized()
@Controller('')
export class MastersController extends BaseController {
  private readonly logger = new Logger(MastersController.name);

  constructor(
    private readonly ballsService: BallsService,
    private readonly subscriptionGroupsService: SubscriptionGroupsService,
  ) {
    super();
  }

  static ERROR_CODES = {};

  get EC() {
    return MastersController.ERROR_CODES;
  }

  @ApiOperation({
    summary: '[authorized] Gets pitch types',
    description: 'List all pitch types',
    tags: ['master'],
  })
  @CodedMethod('GSPT')
  @Get('pitch-types')
  async getSupportedPitchTypes(@Req() req: AppExtendedRequest) {
    const cbuilder = this.getCodeBuilder();

    const result = await this.ballsService.getPitchTypes();

    return {
      pitchTypes: result.pitchTypes,
    };
  }

  @ApiOperation({
    summary: '[authorized]List subscription groups',
    description: 'List all subscription groups',
    tags: ['master'],
  })
  @CodedMethod('GIG')
  @Get('subscription-groups')
  async listSubscriptionGroups() {
    const cbuilder = this.getCodeBuilder();

    const result = await this.subscriptionGroupsService.getSubscriptionGroups();

    return {
      subscriptionGroups: result.subscriptionGroups,
      total: result.total,
    };
  }
}

