import {
  Column,
  Entity,
  JoinTable,
  ManyToMany,
  OneToMany,
  PrimaryGeneratedColumn,
} from 'typeorm';

import { ItemAiCoach } from '@/app/models/item-ai-coach';
import { ItemBall } from '@/app/models/item-ball';
import { Subscription } from '@/app/models/subscription';
import { SubscriptionItem } from '@/app/models/subscription-item';

@Entity('items', { schema: 'public' })
export class Item {
  @PrimaryGeneratedColumn('uuid', { name: 'id' })
  id: string;

  @Column('text', { name: 'name' })
  name: string;

  @Column('text', { name: 'description', nullable: true })
  description: string | null;

  @Column('boolean', { name: 'is_paid' })
  isPaid: boolean;

  @Column('boolean', { name: 'is_subscription' })
  isSubscription: boolean;

  @Column('timestamp with time zone', {
    name: 'created_at',
    default: () => 'now()',
  })
  createdAt: Date;

  @Column('timestamp with time zone', {
    name: 'updated_at',
    default: () => 'now()',
  })
  updatedAt: Date;

  @OneToMany(() => SubscriptionItem, (si) => si.item)
  subscriptionItems: SubscriptionItem[];

  @OneToMany(() => ItemBall, (itemBall) => itemBall.item)
  balls: ItemBall[];

  @OneToMany(() => ItemAiCoach, (itemAiCoach) => itemAiCoach.item)
  aiCoachs: ItemAiCoach[];

  @ManyToMany(() => Subscription, (subscription) => subscription.items)
  @JoinTable({
    name: 'subscriptions_items',
    joinColumn: { name: 'item_id', referencedColumnName: 'id' },
    inverseJoinColumn: { name: 'subscription_id', referencedColumnName: 'id' },
  })
  subscriptions: Subscription[];
}

