import { IPostgresInterval } from 'postgres-interval';
import {
  Column,
  Entity,
  JoinColumn,
  ManyToOne,
  OneToMany,
  PrimaryGeneratedColumn,
} from 'typeorm';

import { Item } from '@/app/models/item';
import { SubscriptionItem } from '@/app/models/subscription-item';
import { TeamItemAiCoach } from '@/app/models/team-item-ai-coach';

@Entity('item_ai_coachs', { schema: 'public' })
export class ItemAiCoach {
  @PrimaryGeneratedColumn('uuid', { name: 'id' })
  id: string;

  @Column('uuid', { name: 'item_id' })
  itemId: string;

  @Column('bigint', { name: 'available_count' })
  availableCount: number;

  @Column('interval', { name: 'validity_period', nullable: true })
  validityPeriod: IPostgresInterval;

  @Column('integer', { name: 'priority' })
  priority: number;

  @Column('timestamp with time zone', {
    name: 'created_at',
    default: () => 'now()',
  })
  createdAt: Date;

  @Column('timestamp with time zone', {
    name: 'updated_at',
    default: () => 'now()',
  })
  updatedAt: Date;

  @ManyToOne(() => Item, (item) => item.aiCoachs)
  @JoinColumn({ name: 'item_id', referencedColumnName: 'id' })
  item: SubscriptionItem;

  @OneToMany(
    () => TeamItemAiCoach,
    (teamItemAiCoach) => teamItemAiCoach.itemAiCoach,
  )
  teamItemAiCoachs: TeamItemAiCoach[];
}

