// Package imports:
import 'package:collection/collection.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/plan.dart';
import 'package:baseball_detector_flutter/data/models/subscription_group.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';

part 'subscription_groups_controller.g.dart';

@riverpod
Future<List<SubscriptionGroup>> subscriptionGroupsController(Ref ref) async {
  final repository = ref.watch(repositoryProvider);
  final result = await repository.getSubscriptionGroups();

  return result.fold(
    (failure) => throw Exception(failure.message),
    (groups) => groups,
  );
}

@riverpod
Future<List<Plan>> plansController(Ref ref) async {
  final groups = await ref.watch(subscriptionGroupsControllerProvider.future);

  // すべてのグループから Plan を抽出してフラットにする
  final allPlans = groups.expand((group) => group.plans).toList();

  // ID でソート（昇順）
  return allPlans.sorted((a, b) {
    final aId = a.id ?? '';
    final bId = b.id ?? '';
    return aId.compareTo(bId);
  });
}

