@riverpod
Future<List<AppStoreProduct>> subscriptionPlansController(Ref ref) async {
  if (!isIos) return [];

  // SubscriptionGroup から Plan データを取得
  final subscriptionGroups = await ref.watch(subscriptionGroupsControllerProvider.future);

  // すべてのグループから subscriptions を取得してフラット化
  final plans = subscriptionGroups
      .expand((group) => group.subscriptions)
      .where((plan) => plan.isActive && plan.isPaid)
      .toList();

  if (plans.isEmpty) return [];

  // Plan の platformConfig から App Store 商品 ID を抽出
  final productIds = plans
      .map((plan) {
        final platformConfig = plan.platformConfig;
        if (platformConfig is Map<String, dynamic>) {
          final appleConfig = platformConfig['apple'];
          if (appleConfig is Map<String, dynamic>) {
            return appleConfig['productId'] as String?;
          }
        }
        // フォールバック: Plan ID から App Store 商品 ID を推測
        return switch (plan.id) {
          '00000001-0000-0050-0000-000000000000' =>
            Constants.appStoreProductIdLight,
          '00000001-0000-0100-0000-000000000000' =>
            Constants.appStoreProductIdStandard,
          '00000001-0000-0300-0000-000000000000' =>
            Constants.appStoreProductIdPremium,
          _ => null,
        };
      })
      .whereType<String>()
      .toSet();

  if (productIds.isEmpty) return [];

  // iOS の App Store Connect に登録されている商品情報を取得
  final appStoreProducts =
      await InAppPurchase.instance.queryProductDetails(productIds);

  // API から取得した Plan と App Store Connect の商品を照合
  return appStoreProducts.productDetails
      .sorted((a, b) => a.rawPrice.compareTo(b.rawPrice))
      .map(
    (product) {
      final p = (product as AppStoreProduct2Details).sk2Product;
      return AppStoreProduct(
        planType: PlanType.fromId(p.id),
        productDetails: product,
        id: p.id,
        displayName: p.displayName,
        displayPrice: p.displayPrice,
        description: p.description,
        price: p.price,
        type: p.type,
        priceLocale: p.priceLocale,
        subscription: p.subscription,
      );
    },
  ).toList();
}

