     1→// Package imports:
     2→import 'package:collection/collection.dart';
     3→import 'package:hooks_riverpod/hooks_riverpod.dart';
     4→import 'package:in_app_purchase/in_app_purchase.dart';
     5→import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
     6→import 'package:riverpod_annotation/riverpod_annotation.dart';
     7→
     8→// Project imports:
     9→import 'package:baseball_detector_flutter/constants.dart';
    10→import 'package:baseball_detector_flutter/controllers/subscription_groups_controller.dart';
    11→import 'package:baseball_detector_flutter/data/models/app_store_plan.dart';
    12→import 'package:baseball_detector_flutter/utils/platform.dart';
    13→
    14→part 'subscription_plans_controller.g.dart';
    15→
    16→@riverpod
    17→Future<List<AppStoreProduct>> subscriptionPlansController(Ref ref) async {
    18→  if (!isIos) return [];
    19→
    20→  // API から Plan データを取得
    21→  final plans = await ref.watch(plansControllerProvider.future);
    22→
    23→  // App Store Connect の商品 ID を生成
    24→  final productIds = plans
    25→      .map((plan) {
    26→        // Plan の ID から App Store の商品 ID を取得
    27→        return switch (plan.id) {
    28→          '00000001-0000-0050-0000-000000000000' =>
    29→            Constants.appStoreProductIdLight,
    30→          '00000001-0000-0100-0000-000000000000' =>
    31→            Constants.appStoreProductIdStandard,
    32→          '00000001-0000-0300-0000-000000000000' =>
    33→            Constants.appStoreProductIdPremium,
    34→          _ => null,
    35→        };
    36→      })
    37→      .whereType<String>()
    38→      .toSet();
    39→
    40→  if (productIds.isEmpty) return [];
    41→
    42→  // iOS の App Store Connect に登録されている商品情報を取得
    43→  final appStoreProducts =
    44→      await InAppPurchase.instance.queryProductDetails(productIds);
    45→
    46→  // API から取得した Plan と App Store Connect に
    47→  // 登録されている product の id が一致するものだけを返す
    48→  return appStoreProducts.productDetails
    49→      .sorted((a, b) => a.rawPrice.compareTo(b.rawPrice))
    50→      // 価格情報を付与して返す
    51→      .map(
    52→    (product) {
    53→      final p = (product as AppStoreProduct2Details).sk2Product;
    54→      return AppStoreProduct(
    55→        planType: PlanType.fromId(p.id),
    56→        productDetails: product,
