import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/team_plan.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';

String usePlanNameFromTeamPlan(TeamPlan? teamPlan) {
  final context = useContext();
  final plan = teamPlan?.plan;

  if (plan == null || plan.id == null) {
    return context.l10n.settings_page__no_plan_name;
  }

  // Plan の名前から表示名を決定
  return _getPlanDisplayName(context, plan.id!, plan.name);
}

String? usePlanNameFromPlanId(String? id) {
  final context = useContext();
  if (id == null) {
    return null;
  }

  // Plan ID から表示名を決定（名前がない場合のフォールバック）
  return _getPlanDisplayName(context, id, null);
}

String _getPlanDisplayName(dynamic context, String planId, String? planName) {
  // Plan ID に基づいて適切な表示名を返す
  // まず、既知の ID の場合は多言語対応の表示名を使用
  final displayName = switch (planId) {
    '00000001-0000-0050-0000-000000000000' =>
      context.l10n.subscription_page__plan_light,
    '00000001-0000-0100-0000-000000000000' =>
      context.l10n.subscription_page__plan_standard,
    '00000001-0000-0300-0000-000000000000' =>
      context.l10n.subscription_page__plan_premium,
    _ => planName, // 新しいプランの場合は API から取得した名前を使用
  };

  return displayName ?? context.l10n.settings_page__no_plan_name;
}

