            : context.l10n
                .settings_page__subscription_downgrade_scheduled_without_plan(
                formatDate(downgradeScheduledAt),
              ),
      );
    }
    if ((cancelScheduledAt?.isAfter(now) ?? false)) {
      lines.add(
        context.l10n.settings_page__subscription_cancel_scheduled(
          formatDate(cancelScheduledAt),
        ),
      );
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        const Gap(4),
        for (final line in lines)
          Text(
            line,
            style: theme.textTheme.bodyMedium?.copyWith(
              color: theme.colorScheme.onSurfaceVariant,
            ),
          ),
      ],
    );
  }

  ({String planName, int? ballCount, int? aiCoachCount}) getPlanFeatures(
    Plan plan,
    BuildContext context,
  ) {
    // Plan ID に基づいて多言語対応の表示名を取得
    final planName = switch (plan.id) {
      '00000001-0000-0050-0000-000000000000' =>
        context.l10n.subscription_page__plan_light,
      '00000001-0000-0100-0000-000000000000' =>
        context.l10n.subscription_page__plan_standard,
      '00000001-0000-0300-0000-000000000000' =>
        context.l10n.subscription_page__plan_premium,
      _ => plan.name ?? '', // 新しいプランの場合は API から取得した名前を使用
    };

    return (
      planName: planName,
      ballCount: plan.maxBalls,
      aiCoachCount: plan.maxAiCoachs,
    );
  }
}

class _CurrentBadgeWithSchedule extends StatelessWidget {
