import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:native_device_orientation/native_device_orientation.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/subscription_controller.dart';
import 'package:baseball_detector_flutter/data/models/app_store_plan.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/utils/screen_orientation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_debounce.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';

/// サブスクリプションページへ遷移する（必要に応じて画面の向きを固定）。
ValueSetter<Team?> useSubscriptionPage() {
  final context = useContext();
  final ref = useWidgetRef();

  return useDebounce<Team?>((team) async {
    // 実行時点の最新の entitlement を取得
    final latestEntitlement = ref.read(subscriptionControllerProvider);

    latestEntitlement.when(
        loading: () {},
        error: (_, __) {},
        data: (data) async {
          if (team == null) return;
          // CurrentEntitlement から PlanType を算出
          final planType = data?.productId == null
              ? null
              : PlanType.fromId(data!.productId!);

          ScreenOrientation.lock([NativeDeviceOrientation.portraitUp]);
          await Future.delayed(const Duration(milliseconds: 300));
          if (!context.mounted) return;
          await Navigator.of(context, rootNavigator: true).pushNamed(
            AppRouter.subscriptionPage,
            arguments: {'team': team, 'currentPlan': planType},
          );
        });
  });
}

