                  error: (error, stack) => Center(
                    child: Column(
                      children: [
                        const Icon(
                          Icons.error_outline,
                          size: 48,
                          color: Colors.red,
                        ),
                        const Gap(16),
                        Text(
                          context.l10n.subscription_page__loading_plans_error,
                          style: theme.textTheme.bodyLarge,
                        ),
                        const Gap(8),
                        TextButton(
                          onPressed: () =>
                              ref.refresh(subscriptionPlansControllerProvider),
                          child: Text(
                              context.l10n.subscription_page__retry_button),
                        ),
                      ],
                    ),
                  ),
                ),
              ),
            ),
          ),
        ),
      ],
    );
  }

  String _getPlanDisplayName(
    BuildContext context,
    String? planId,
    String? planName,
  ) {
    if (planId == null) return '';

    // 既知のプラン ID の場合は多言語対応の表示名を返す
    return switch (planId) {
      '00000001-0000-0050-0000-000000000000' =>
        context.l10n.subscription_page__plan_light,
      '00000001-0000-0100-0000-000000000000' =>
        context.l10n.subscription_page__plan_standard,
      '00000001-0000-0300-0000-000000000000' =>
        context.l10n.subscription_page__plan_premium,
      _ => planName ?? '', // 新しいプランの場合は API から取得した名前を使用
    };
  }
}

