  static const String onboardingPage = '/onboardingPage';
  static const String recordingPage = '/recordingPage';
  static const String signUpPage = '/signUpPage';
  static const String splashPage = '/splashPage';
  static const String updateRequiredPage = '/updateRequiredPage';
  static const String videoPlayerFullScreenPage = '/videoPlayerFullScreenPage';
  static const String inAppPurchaseDebugPage = '/iap-debug';
  static const String subscriptionPage = '/subscription';

  // NOTE: These dialog names are for logging purposes only; do not pass them to pushNamed.
  static const String cancellableLoadingDialog = '/cancellableLoadingDialog';
  static const String changePasswordConfirmationDialog =
      '/changePasswordConfirmationDialog';
  static const String createPlayerDialog = '/createPlayerDialog';
