  static const Set<String> ignoreRoutesForLogging = {loadingDialog};

  static Widget getPage(BuildContext context, RouteSettings routeSettings) {
    switch (routeSettings.name) {
      case cancelSubscriptionPage:
        return const CancelSubscriptionPage();
      case forgotPasswordPage:
        return const ForgotPasswordPage();
      case loginPage:
        return const LoginPage();
      case signUpPage:
        return const SignUpPage();
      case confirmCodePage:
        return const ConfirmCodePage();
      case forceMigrationPage:
        return const ForceMigrationPage();
      case deleteAccountPage:
        if (routeSettings.arguments != null) {
          final shouldShowCancelSubscriptionMessage =
              (routeSettings.arguments as Map<String, dynamic>)[
                  'shouldShowCancelSubscriptionMessage'] as bool;
          return DeleteAccountPage(
            shouldShowCancelSubscriptionMessage:
                shouldShowCancelSubscriptionMessage,
          );
        }
        return DeleteAccountPage();

      case recordingPage:
        final sessionId = (routeSettings.arguments
            as Map<String, dynamic>)['sessionId'] as String;
        final sessionCreatedAt = (routeSettings.arguments
            as Map<String, dynamic>)['sessionCreatedAt'] as DateTime;
        final teamId = (routeSettings.arguments
            as Map<String, dynamic>)['teamId'] as String;
        return RecordingPage(
          sessionId: sessionId,
          sessionCreatedAt: sessionCreatedAt,
          teamId: teamId,
        );
      case homePage:
        return HomePage();
      case splashPage:
        return const SplashPage();
      case maintenancePage:
        return const MaintenancePage();
      case updateRequiredPage:
        return const UpdateRequiredPage();
      case onboardingPage:
        return const OnboardingPage();
      case videoPlayerFullScreenPage:
        final ball = (routeSettings.arguments as Map<String, dynamic>)['ball'];
        final videoURL =
            (routeSettings.arguments as Map<String, dynamic>)['videoURL'];
        final fileName =
            (routeSettings.arguments as Map<String, dynamic>)['fileName'];
        final isShareAvailable = (routeSettings.arguments
            as Map<String, dynamic>)['isShareAvailable'];

        return VideoPlayerFullScreenPage(
          ball: ball,
          videoURL: videoURL,
          fileName: fileName,
          isShareAvailable: isShareAvailable,
        );
      case inAppPurchaseDebugPage:
        return const InAppPurchaseDebugPage();
      case subscriptionPage:
        final team =
            (routeSettings.arguments as Map<String, dynamic>)['team'] as Team;
        final currentPlanId = (routeSettings.arguments
            as Map<String, dynamic>)['currentPlanId'] as String?;

        return SubscriptionPage(team: team, currentPlanId: currentPlanId);
      default:
        throw 'Undefined route "${routeSettings.name}" found.';
    }
  }

  static PageRouteBuilder<dynamic> generateRoute(RouteSettings settings) {
    if (settings.name == subscriptionPage) {
      return PageRouteBuilder<dynamic>(
        settings: settings,
        pageBuilder: (context, animation, secondaryAnimation) =>
            getPage(context, settings),
        transitionsBuilder: (context, animation, secondaryAnimation, child) {
          const begin = Offset(0.0, 1.0);
          const end = Offset.zero;
          const curve = Curves.easeOutCubic;

          var tween = Tween(begin: begin, end: end).chain(
            CurveTween(curve: curve),
          );

          return SlideTransition(
            position: animation.drive(tween),
            child: child,
          );
        },
        transitionDuration: const Duration(milliseconds: 400),
        reverseTransitionDuration: const Duration(milliseconds: 200),
        fullscreenDialog: true,
      );
    }

    return PageRouteBuilder<dynamic>(
      settings: settings,
      pageBuilder: (context, _, __) => getPage(context, settings),
    );
  }
}

